import { Node } from '../interfaces';

export const UNKNOWN = {};

export function gatherPossibleValues(node: Node, set: Set<string|{}>) {
	if (node.type === 'Literal') {
		set.add(node.value);
	}

	else if (node.type === 'ConditionalExpression') {
		gatherPossibleValues(node.consequent, set);
		gatherPossibleValues(node.alternate, set);
	}

	else {
		set.add(UNKNOWN);
	}
}

function readAttribute(parser: Parser, uniqueNames: Set<string>) {
	const start = parser.index;

	if (parser.eat('{{')) {
		parser.allowWhitespace();
		parser.eat('...', true, 'Expected spread operator (...)');

		const expression = readExpression(parser);

		parser.allowWhitespace();
		parser.eat('}}', true);

		return {
			start,
			end: parser.index,
			type: 'Spread',
			expression
		};
	}

	let name = parser.readUntil(/(\s|=|\/|>)/);
	if (!name) return null;
	if (uniqueNames.has(name)) {
		parser.error('Attributes need to be unique', start);
	}

	uniqueNames.add(name);

	parser.allowWhitespace();

	const attribute = readDirective(parser, start, name);
	if (attribute) return attribute;

	let value = parser.eat('=') ? readAttributeValue(parser) : true;

	return {
		start,
		end: parser.index,
		type: 'Attribute',
		name,
		value,
	};
}
